from flask import Flask, request, jsonify
import pandas as pd
import tensorflow as tf
from tensorflow.keras.models import Sequential
from tensorflow.keras.layers import Dense, Flatten, Conv2D, MaxPooling2D
from tensorflow.keras.utils import to_categorical
from werkzeug.utils import secure_filename
import os
import numpy as np

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads/'

# Initialize a simple CNN model
def create_model(input_shape, num_classes):
    model = Sequential([
        Conv2D(32, (3, 3), activation='relu', input_shape=input_shape),
        MaxPooling2D((2, 2)),
        Flatten(),
        Dense(128, activation='relu'),
        Dense(num_classes, activation='softmax')
    ])
    model.compile(optimizer='adam', loss='categorical_crossentropy', metrics=['accuracy'])
    return model

# Load and preprocess data
def load_data(file_path):
    data = pd.read_csv(file_path)
    images = data.iloc[:, 1:].values.reshape(-1, 28, 28, 1) / 255.0
    labels = to_categorical(data.iloc[:, 0].values)
    return images, labels

# Train the model
def train_model(images, labels):
    input_shape = images.shape[1:]
    num_classes = labels.shape[1]
    model = create_model(input_shape, num_classes)
    model.fit(images, labels, epochs=5, batch_size=32, validation_split=0.2)
    model.save('community_model.h5')

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'})
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'})
    if file:
        filename = secure_filename(file.filename)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(file_path)
        images, labels = load_data(file_path)
        train_model(images, labels)
        return jsonify({'message': 'Model trained successfully'})

if __name__ == '__main__':
    if not os.path.exists(app.config['UPLOAD_FOLDER']):
        os.makedirs(app.config['UPLOAD_FOLDER'])
    app.run(debug=True)